import React from "react";

function Dashboard({ upcomingActivity, onAddActivity, onViewCalendar }) {
  const cardStyle = {
    border: "1px solid #e2e8f0",
    borderRadius: 12,
    padding: "1rem",
    background: "#f8fafc",
    marginBottom: "1rem"
  };

  const buttonStyle = {
    border: "none",
    padding: "0.7rem 1.1rem",
    borderRadius: 8,
    fontWeight: 600,
    cursor: "pointer",
    marginRight: "0.75rem"
  };

  return (
    <div>
      <h2 style={{ marginTop: 0 }}>Dashboard</h2>

      <div style={cardStyle}>
        <h3 style={{ marginTop: 0 }}>Upcoming Activity</h3>
        {upcomingActivity ? (
          <div>
            <p style={{ margin: "0.25rem 0" }}>
              <strong>Name:</strong> {upcomingActivity.name}
            </p>
            <p style={{ margin: "0.25rem 0" }}>
              <strong>Date/Time:</strong>{" "}
              {new Date(upcomingActivity.dateTime).toLocaleString()}
            </p>
            <p style={{ margin: "0.25rem 0" }}>
              <strong>Weather:</strong> {upcomingActivity.weatherSummary}
            </p>
          </div>
        ) : (
          <p style={{ marginBottom: 0 }}>No upcoming activities yet.</p>
        )}
      </div>

      <button
        onClick={onAddActivity}
        style={{ ...buttonStyle, background: "#2563eb", color: "#ffffff" }}
      >
        Add Activity
      </button>
      <button
        onClick={onViewCalendar}
        style={{ ...buttonStyle, background: "#e2e8f0", color: "#0f172a" }}
      >
        View Calendar
      </button>
    </div>
  );
}

export default Dashboard;
